package cz.uhk.monkifyimport androidx.compose.runtime.Composableimport androidx.compose.runtime.LaunchedEffectimport androidx.compose.ui.Alignmentimport androidx.compose.ui.unit.DpSizeimport androidx.compose.ui.unit.dpimport androidx.compose.ui.window.FrameWindowScopeimport androidx.compose.ui.window.Windowimport androidx.compose.ui.window.WindowPositionimport androidx.compose.ui.window.WindowStateimport androidx.compose.ui.window.applicationimport cz.uhk.monkify.di.initKoinimport java.awt.Dimensionfun main() {    initKoin()    initializeFirebase()    application {        Window(            onCloseRequest = ::exitApplication,            title = "Monkify",            state = WindowState(                size = DpSize(width = 860.dp, height = 860.dp),                position = WindowPosition.Aligned(Alignment.Center),            ),        ) {            setMinimumWindowSize()            App()        }    }}@Composableprivate fun FrameWindowScope.setMinimumWindowSize() {    LaunchedEffect(Unit) {        window.minimumSize = Dimension(440, 860)    }}